  MatDialogClose,
  MatDialogContent,
  MatDialogTitle,
} from '@angular/material/dialog';
import { DomSanitizer, SafeResourceUrl } from '@angular/platform-browser';

export interface ReceiptPreviewDialogData {
  attachmentFileName: string;
  mimeType: string;
  previewUrl: string;
}

@Component({
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    MatButtonModule,
    MatDialogActions,
    MatDialogClose,
    MatDialogContent,
    MatDialogTitle,
  ],
  selector: 'app-receipt-preview-dialog',
  templateUrl: './receipt-preview-dialog.component.html',
})
export class ReceiptPreviewDialogComponent {
  protected readonly data = inject(MAT_DIALOG_DATA) as ReceiptPreviewDialogData;

  protected readonly isImage = computed(() =>
    this.data.mimeType.startsWith('image/'),
  );

  protected readonly isPdf = computed(
    () => this.data.mimeType === 'application/pdf',
  );

  private readonly sanitizer = inject(DomSanitizer);

  protected readonly safePdfPreviewUrl = computed<null | SafeResourceUrl>(
    () => {
      if (!this.isPdf()) {
        return null;
      }
      return this.sanitizer.bypassSecurityTrustResourceUrl(
        this.data.previewUrl,
      );
    },
  );
}
<h2 mat-dialog-title>{{ data.attachmentFileName }}</h2>
<mat-dialog-content class="max-h-[80vh]">
  @if (isImage()) {
    <img
      [src]="data.previewUrl"
      [alt]="data.attachmentFileName"
      class="max-h-[70vh] w-full rounded-xl object-contain"
    />
  } @else if (isPdf()) {
    <iframe
      [src]="safePdfPreviewUrl()"
      title="Receipt preview"
      class="h-[70vh] w-full rounded-xl border border-outline-variant"
    ></iframe>
  } @else {
    <p class="text-on-surface-variant text-sm">
      Preview is not supported for this file type.
    </p>
  }
</mat-dialog-content>
<mat-dialog-actions align="end">
  <a
